using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// --- Options with a default resolver (handles any type) ---
var webOptions = new JsonSerializerOptions(JsonSerializerDefaults.Web);

// 1) GetTypeInfo<T>() — returns JsonTypeInfo<Person> directly, no cast needed.
JsonTypeInfo<Person> personInfo = webOptions.GetTypeInfo<Person>();
Console.WriteLine($"GetTypeInfo<Person> resolved: {personInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Alice", 42), personInfo);
Console.WriteLine($"Serialized: {json}");

// 2) TryGetTypeInfo<T>() — probe without throwing.
if (webOptions.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? probed))
{
    Console.WriteLine($"TryGetTypeInfo<Person> succeeded: {probed!.Type.Name}");
}

// --- Options with a source-gen resolver that only knows about Person ---
var restrictedOptions = new JsonSerializerOptions
{
    TypeInfoResolver = PersonOnlyContext.Default
};

// Person is in the context → should succeed
if (restrictedOptions.TryGetTypeInfo<Person>(out var personResult))
    Console.WriteLine($"TryGet Person on restricted options: found ({personResult!.Type.Name})");
else
    Console.WriteLine("TryGet Person on restricted options: NOT found");

// Order is NOT in the context → should return false, no exception
if (restrictedOptions.TryGetTypeInfo<Order>(out var orderResult))
    Console.WriteLine($"TryGet Order on restricted options: found ({orderResult!.Type.Name})");
else
    Console.WriteLine("TryGet Order on restricted options: NOT found");

// --- Types ---
public record Person(string Name, int Age);
public record Order(int Id, decimal Total);

[JsonSerializable(typeof(Person))]          // only Person is registered
public partial class PersonOnlyContext : JsonSerializerContext;

